import React from 'react';
import { ExpandButton } from '../shared/components/expand-button';

interface DefaultExpandIconProps<RecordType> {
  prefixCls: string;
  onExpand: (record: RecordType, e: React.MouseEvent<HTMLElement>) => void;
  record: RecordType;
  expanded: boolean;
  expandable: boolean;
}

function renderExpandIcon() {
  return function expandIcon<RecordType>({
    prefixCls,
    onExpand,
    record,
    expanded,
    expandable,
  }: DefaultExpandIconProps<RecordType>) {
    const onClick: React.MouseEventHandler<HTMLElement> = event => {
      onExpand(record, event);
      event.stopPropagation();
    };

    return (
      <ExpandButton
        className={`${prefixCls}-row-expand-icon`}
        isExpanded={expanded}
        onClick={onClick}
        iconType="ExpandDownFilled"
        asPlaceholder={!expandable}
      />
    );
  };
}

export default renderExpandIcon;
